nta.declaration:
__DATA__


const double g_value = 0.45; //Value gotten from Rasmus
const double r213[3] = {1.213, 3.64, 372};
const double r215[3] = {1.215, 5.46, 422};
const double r217[3] = {1.217, 3.64, 379};
const double r229[3] = {1.229, 5.18, 758};
const double r231[3] = {1.231, 6.86, 758};
const double r233[3] = {1.233, 7, 758};
const double current_room[3] = r213;
const int init_time = __INIT_TIME__;
const int control_interval = 30;
const double init_temp = __INIT_TEMP__;

const double alpha_a = __ALPHA_A__;
const double alpha_s = __ALPHA_S__;
const double alpha_h = __ALPHA_H__;
const double alpha_v = __ALPHA_V__;
const double alpha_o = __ALPHA_O__;

int counter = init_time;


broadcast chan tik;

hybrid clock T_r;
hybrid clock cost = 0;

double blinds = __BLINDS__;
double sun_block = 1;
bool blocked = __BLOCKED__;

double E_s;
double T_a;
double H;
double C;
double w;

double T_v;
double S;
double O;
double T_h;

/*
Blinds Blocked
*/
void blinds_blocked(){
    if (w >= 10) {
        blocked = true;
    }
    if (w <= 8) {
        blocked = false;
    }
}


/*
Solar
*/
double window_size = current_room[1];
void update_solar() {
    if(blinds == 0){
        sun_block = 1;
    }
    else if(blinds == 1){
        sun_block = 0;
    }
    else{
        sun_block = 0.2/blinds;
    }
    S = E_s * g_value * window_size;
}


/*
Heater
*/
double heater_temp;
void update_heat() {
    if(T_r <= H){
        T_h = 0;
    }
    else{
        if (T_a < 12) {
            heater_temp = 77;
        } else if (-12 < T_a && T_a <= 5) {
            heater_temp = -T_a + 65;
        } else if (5 < T_a && T_a <= 20) {
            heater_temp = -1.33 * T_a + 66.67;
        } else if (20 < T_a) {
            heater_temp = 40;
        }
        T_h = heater_temp - T_r;
    }
}


/*
Ventilation
*/
double ventilation_valve = 0.3;
double ventilation_temp = 0;
void update_vent() {
    if(T_r > C){
        ventilation_valve = 0.3;
    }
    else{
        ventilation_valve = 1;
    }

    ventilation_temp = T_a;
    if (T_a <= 5){
        ventilation_temp = 21;
    } 
    else if (5 < T_a <= 17.8){
        ventilation_temp = -0.25 * T_a + 22.25;
    }

    T_v = ventilation_valve * (ventilation_temp - T_r);
}


/*
Occupancy
*/
const int probabilities[4][7] = {
    {50, 75, 90, 95, 98, 99, 100},  // Probabilities for 0-8 AM
    {10, 25, 45, 65, 80, 90, 100}, // Probabilities for 8 AM-12 PM
    {5, 15, 30, 50, 70, 85, 100},  // Probabilities for 12-4 PM
    {20, 45, 65, 80, 90, 96, 100}   // Probabilities for 4-12 AM
};


const int energy_people_office = 250;
const int energy_people_group = 150;
const bool is_group = true;
const int P = 5;

int E_p = 0;
int occupancy = 0;
double random_number = 0;
clock y;

void choose_occupancy(int time_frame) {
    random_number = random(100);

    if (random_number <= probabilities[time_frame][0]) {  
        occupancy = 1;
    } else if (random_number <= probabilities[time_frame][1]) {  
        occupancy = 2;
    } else if (random_number <= probabilities[time_frame][2]) { 
        occupancy = 3;
    } else if (random_number <= probabilities[time_frame][3]) {  
        occupancy = 4;
    } else if (random_number <= probabilities[time_frame][4]) {
        occupancy = 5;
    } else if (random_number <= probabilities[time_frame][5]) {
        occupancy = 6;
    } else if (random_number <= probabilities[time_frame][6]) {
        occupancy = 7;
    }   
}


void update_occu() {
    if(C - H == 1){
        if(y >= P){
            if(counter < 480){
                choose_occupancy(0); //Before 08:00
            } else if(counter >= 480 && counter < 720){
                choose_occupancy(1); //08:00 to 12:00
            } else if(counter >= 480 && counter < 720){
                choose_occupancy(2); //12:00 to 16:00
            } else{
                choose_occupancy(3); //After 16:00
            }
            y = 0;
        }
        if (is_group) {
            E_p = energy_people_group;
        } else {
            E_p = energy_people_office;
        }
        O = occupancy * E_p;
    }
    else{
        O = 0;
        occupancy = 0;
    }
}



/*
Initializer
*/
void initialize() {
    if(init_temp == 0.0){
        T_r = data[init_time][1];
    }
    else{
        T_r = init_temp;
    }

    E_s = data[init_time][0];
    T_a = data[init_time][2];
    H = data[init_time][3];
    C = data[init_time][4];
    w = data[init_time][6];
}

template.declaration:
clock x;
int period = 1;

void update_values(){
    E_s = data[counter][0];
    T_a = data[counter][2];
    H = data[counter][3];
    C = data[counter][4];
    w = data[counter][6];

    blinds_blocked();
    update_solar();
    update_heat();
    update_vent();
    update_occu();
}
